supported_countries = {
    'United States', 'United Kingdom', 'Germany', 'Canada', 'France', 
    'India', 'Turkey', 'Italy', 'Belgium', 'Brazil', 'Ireland', 
    'Poland', 'Spain', 'Japan', 'Australia'
}
restricted_countries = {'China', 'Crimea', 'Cuba', 'Iran', 'North Korea', 'Sudan', 'Syria'}

def is_standalone_available(country):
    if country in restricted_countries:
        return False
    return country in supported_countries

# Example usage:
print(is_standalone_available('Germany'))  # Output: True
print(is_standalone_available('North Korea'))  # Output: False
